#include "interface.h"

#include <stdint.h>

uint64_t run(const int32_t* deltas, size_t count, int iters) {
  const int64_t offset = 0x9E3779B1LL;
  const uint64_t offset_sum = (uint64_t)count * (uint64_t)offset;
  uint64_t total = 0;
  for (int iter = 0; iter < iters; ++iter) {
    int64_t current = 0;
    int64_t prefix_sum = 0;
    size_t i = 0;
    size_t limit = count & ~(size_t)3;
    for (; i < limit; i += 4) {
      current += deltas[i];
      prefix_sum += current;
      current += deltas[i + 1];
      prefix_sum += current;
      current += deltas[i + 2];
      prefix_sum += current;
      current += deltas[i + 3];
      prefix_sum += current;
    }
    for (; i < count; ++i) {
      current += deltas[i];
      prefix_sum += current;
    }
    total = (uint64_t)prefix_sum + offset_sum;
  }
  return total;
}
